mapper.select:
/* com.shop.mapper.partner.selectPartnerList */ SELECT TP.ID AS id, TP.PARTNER_TICKER , TP.PARTNER_TYPE , FN_GET_CODE('10060', TP.PARTNER_TYPE) PARTNER_TYPE_NM, TP.PARTNER_NM, TP.PARTNER_SUB_NM, TP.DOMAIN , TP.SUB_DOMAIN, TP.PHONE_NO, TP.FIRST_GREETING_MESSAGE , TP.CRE_TM AS creTm, TP.CRE_USER AS creUser, FN_GET_USERNAME(TP.CRE_USER) as creUserNm, TP.UPD_TM AS updTm, TP.UPD_USER AS updUser, FN_GET_USERNAME(TP.UPD_USER) as upduserNm FROM TB_PARTNER TP WHERE TP.DEL_YN = 'N'
AND TP.LOGIS_ID = #{logisId}
ORDER BY TP.PARTNER_NM ASC;

/* com.shop.mapper.partner.selectPartnerListForSearching */ SELECT TP.ID AS id, TP.PARTNER_TICKER , TP.PARTNER_TYPE , FN_GET_CODE('10060', TP.PARTNER_TYPE) PARTNER_TYPE_NM, TP.PARTNER_NM, TP.PARTNER_SUB_NM, TP.DOMAIN , TP.SUB_DOMAIN, TP.PHONE_NO, TP.FIRST_GREETING_MESSAGE , TP.CRE_TM AS creTm, TP.CRE_USER AS creUser, FN_GET_USERNAME(TP.CRE_USER) as creUserNm, TP.UPD_TM AS updTm, TP.UPD_USER AS updUser, FN_GET_USERNAME(TP.UPD_USER) as upduserNm FROM TB_PARTNER TP WHERE TP.DEL_YN = 'N'
AND TP.PARTNER_NM LIKE CONCAT('%', #{partnerNm}, '%')
ORDER BY TPPARTNER_NM ASC;

mapper.update:
/* com.shop.mapper.partner.updatePartner */
UPDATE TB_PARTNER
SET
    UPD_TM = NOW(),
    UPD_USER = #{updUser}

        , PARTNER_TYPE = #{partnerType}


        , PARTNER_NM = #{partnerNm}


        , FIRST_GREETING_MESSAGE = #{firstGreetingMessage}


        , PARTNER_TICKER = #{partnerTicker}


        , PARTNER_SUB_NM = #{partnerSubNm}


        , DOMAIN = #{domain}


        , PHONE_NO = #{phoneNo}


        , REP_NM = #{repNm}


        , SUB_DOMAIN = #{subDomain}

WHERE ID = #{id}

/* com.shop.mapper.partner.deletePartner */
UPDATE TB_PARTNER
    SET DEL_YN = 'Y'
WHERE ID = #{id}
